fn is_special_number(num: i64) -> bool {
    let s = num.to_string();
    if s != s.chars().rev().collect::<String>() {
        return false;
    }
    let mut count = std::collections::HashMap::new();
    for ch in s.chars() {
        let d = ch.to_digit(10).unwrap() as i64;
        if d == 0 || d > 9 {
            return false;
        }
        *count.entry(d).or_insert(0) += 1;
    }
    for (&d, &cnt) in count.iter() {
        if cnt != d {
            return false;
        }
    }
    true
}

pub fn solve(n: i64) -> i64 {
    let mut current = n + 1;
    loop {
        if is_special_number(current) {
            return current;
        }
        current += 1;
    }
}
